export default function ImportRemainingPage() {
  const [status, setStatus] = useState("")
  const [done, setDone] = useState(false)

  async function handleImport() {
    setStatus("Əlavə məlumatlar idxal edilir...")
    let total = 0
    for (let i = 0; i < BOOKINGS.length; i++) {
      const { error } = await supabase.from("bookings").insert(BOOKINGS[i])
      if (error) { setStatus("Xəta: " + error.message); return }
      total += BOOKINGS[i].length
      setStatus(`Sifarişlər: ${total} / 142`)
    }
    setStatus("✅ Tamamlandı! 142 sifariş əlavə edildi.")
    setDone(true)
  }

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-6">
      <div className="bg-white rounded-2xl border border-gray-100 p-8 max-w-md w-full">
        <h1 className="text-xl font-bold text-gray-900 mb-2">Qalan sifarişlər</h1>
        <p className="text-sm text-gray-500 mb-6">7 maydan sonrakı 142 sifariş əlavə ediləcək</p>
        {!done && (
          <button onClick={handleImport}
            className="w-full bg-blue-500 text-white py-3 rounded-xl font-medium hover:bg-blue-600">
            Əlavə et
          </button>
        )}
        {status && (
          <p className="mt-4 text-sm text-gray-600 bg-gray-50 p-3 rounded-xl">{status}</p>
        )}
      </div>
    </div>
  )
}
